class Tools{getUrlValue(key){const query=window.location.search.substring(1),arr=query.split("&");for(const item of arr){const pair=item.split("=");if(pair[0]===key)return pair[1]}}stringify(obj={}){const arr=[];for(const key in obj)Object.hasOwnProperty.call(obj,key)&&arr.push(`${key}=${obj[key]}`);return arr.join("&")}notify({description:description,closeTimeout:closeTimeout=2e3,type:type="success"}){GrowlNotification.notify({description:description,closeTimeout:closeTimeout,type:type,image:{visible:!0}})}dayjs(date){return(date=new Date(date)).setMinutes(date.getMinutes()-date.getTimezoneOffset()),date.toJSON().substr(0,19).replace(/[T]/," ")}}const $ryTools=new Tools;